import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface RegionSales {
  name: string;
  sales: number;
}

interface WidgetData {
  regions: RegionSales[];
  totalSales: number;
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const metaData = response.meta as MetaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 300, maxWidth: 400, bgcolor: '#2C2C2C' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: metaData.primaryColor, fontWeight: 600 }}>
              Sales Heatmap
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ color: '#FFFFFF' }}>
              Total Sales: ${widgetData.totalSales.toLocaleString()}
            </Typography>
          </Box>

          <PieChart
            height={220}
            series={[
              {
                type: 'pie',
                data: widgetData.regions.map(region => ({
                  id: region.name,
                  value: region.sales,
                  label: region.name,
                })),
                innerRadius: 0.5,
                labelColor: '#FFFFFF',
                color: metaData.accentColor,
              },
            ]}
            margin={{ top: 20, bottom: 20, left: 20, right: 20 }}
            sx={{
              '& .MuiChartsPieLabel-root': {
                fontSize: 12,
                fill: metaData.accentColor,
              },
              '& .MuiChartsPieSlice-root': {
                stroke: metaData.primaryColor,
                strokeWidth: 1,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
